<template>
  <!-- 二维码 -->
  <div class="qrcode">
    <main>
      <span>委托编号</span>
      <h2>{{ code }}</h2>
      <div
        class="animate__animated animate__fadeInDown"
        style="margin-top: 10px"
        id="qrcode"
      ></div>
      <el-button style="margin-top: 16px" @click="load()"
        >下载委托单二维码</el-button
      >
      <el-button
        v-if="success"
        style="margin-top: 16px"
        type="primary"
        @click="home()"
        >返回首页</el-button
      >
    </main>
  </div>
</template>

<script>
// import QRCode from "qrcode";
import QRCode from "qrcodejs2";
import { Notify } from "vant";
export default {
  name: "qrcode",
  data() {
    return {
      code: "",
      success: false,
    };
  },
  created() {
    this.code = this.$route.query.code;
    this.success = this.$route.query.success;

    if (this.success) {
      Notify({ type: "success", message: "下单成功" });
    }
  },
  mounted() {
    this.initCode(this.code);
  },
  methods: {
    home() {
      this.$router.replace({ name: "home" });
    },
    initCode(value) {
      var qrcode = new QRCode(document.getElementById("qrcode"), {
        render: "canvas",
        text: value,
        width: 100,
        height: 100,
        // colorDark: "#DC143C",
        colorDark: "#000000",
        colorLight: "#ffffff",
        correctLevel: QRCode.CorrectLevel.H,
      });
    },
    downLoadImage(canvas) {
      var a = document.createElement("a");
      a.href = canvas.toDataURL();
      a.download = this.code;
      a.click();
    },
    load() {
      let dom = document.getElementById("qrcode");
      let canvas = dom.firstChild;
      this.downLoadImage(canvas);
      console.log("onClick");
    },
  },
};
</script>

<style lang="less">
.qrcode {
  width: 7.5rem;
  height: 13.34rem;
  display: flex;
  align-items: center;
  justify-content: space-around;
  padding: 30px;
  box-sizing: border-box;
  position: relative;

  main {
    h2 {
      font-size: 16px;
    }
    span {
      font-size: 16px;
    }
    height: 200px;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: space-around;
  }
}
</style>